@@ -997,0 +997,44 @@
+#if defined(LINUX) && defined(AMD64)
+VM_Version::VM_Features VM_Version::get_microarch_features(const char microarch_level) {
+  VM_Version::VM_Features features;
+  switch(microarch_level) {
+    case '4':
+      features.set_feature(CPU_AVX512F);
+      features.set_feature(CPU_AVX512BW);
+      features.set_feature(CPU_AVX512CD);
+      features.set_feature(CPU_AVX512DQ);
+      features.set_feature(CPU_AVX512VL);
+      /* FALLTHROUGH */
+    case '3':
+      features.set_feature(CPU_AVX);
+      features.set_feature(CPU_AVX2);
+      features.set_feature(CPU_BMI1);
+      features.set_feature(CPU_BMI2);
+      features.set_feature(CPU_F16C);
+      features.set_feature(CPU_FMA);
+      features.set_feature(CPU_LZCNT);
+      features.set_feature(CPU_MOVBE);
+      features.set_feature(CPU_OSXSAVE);
+      /* FALLTHROUGH */
+    case '2':
+      features.set_feature(CPU_CMPXCHG16);
+      features.set_feature(CPU_LAHFSAHF);
+      features.set_feature(CPU_POPCNT);
+      features.set_feature(CPU_SSE3);
+      features.set_feature(CPU_SSE4_1);
+      features.set_feature(CPU_SSE4_2);
+      features.set_feature(CPU_SSSE3);
+      /* FALLTHROUGH */
+    case '1':
+      // generic and x86-64-v1 have the same set of features
+      set_generic_features(features);
+      break;
+    default:
+      vm_exit_during_initialization(err_msg("VM option 'CPUFeatures=x86-64-v%c' is invalid: "
+        "supported levels are x86-64-v1 through x86-64-v4", microarch_level));
+  }
+
+  return features;
+}
+#endif
+
